    "통합사회1": { goal: "행복, 자연환경, 인권, 시장 등 사회의 핵심 개념을 지리, 역사, 윤리, 일반 사회의 통합적 관점에서 탐구하는 1학년 수능 필수 공통 과목입니다.", contents: [{ t: "📌 영역: 인간, 사회, 환경과 행복", l: ["<span class='k-tag k-know'>지식·이해</span> 다양한 관점의 특징과 삶의 목적, 인권의 역사적 확장 과정", "<span class='k-tag k-skill'>과정·기능</span> 현대 사회의 인권 침해 사례를 조사하고 다각적인 해결 방안 모색하기"] }, { t: "📌 영역: 자연환경과 시장 경제", l: ["<span class='k-tag k-know'>지식·이해</span> 기후/지형이 삶에 미치는 영향, 자본주의 시장 경제의 한계와 국가의 개입", "<span class='k-tag k-skill'>과정·기능</span> 기후 변화로 인한 환경 문제나 시장 실패(독과점, 외부효과) 사례 분석하기"] }], careers: ["행정공무원", "사회학연구원", "도시계획가"], majors: ["사회학과", "행정학과", "사회교육과"] },
