    "지구시스템과학": { goal: "기존 '지구과학Ⅱ'의 대기, 해양, 지질학 심화 파트를 다루며, 지구를 구성하는 각 시스템의 정량적 역학 관계를 수학·물리적 개념을 도입해 분석합니다.", contents: [{ t: "📌 영역: 고체 지구와 유체 지구의 역학", l: ["<span class='k-tag k-know'>지식·이해</span> 지구 자기장, 광물과 암석의 광학적 특성, 지형류, 정역학 평형, 대기 대순환", "<span class='k-tag k-skill'>과정·기능</span> 편광 현미경 관찰을 통해 암석을 분류하고, 해수의 수온-염분도(T-S도)를 수리적으로 해석하여 밀도류 분석하기"] }], careers: ["기상연구원", "해양탐사전문가", "지질연구원"], majors: ["지구시스템과학과", "대기과학과", "해양학과"] },
    "행성우주과학": { goal: "기존 '지구과학Ⅱ'의 천문학 심화 파트로, 천체 좌표계, 외계 행성 탐사, 블랙홀, 우주론 등을 정량적인 천체 물리 공식을 활용해 탐구하는 진로 과목입니다.", contents: [{ t: "📌 영역: 천체 관측과 우주론", l: ["<span class='k-tag k-know'>지식·이해</span> 적도 좌표계, 케플러 궤도 운동, 별의 에너지원(수소 핵융합), 급팽창 우주론", "<span class='k-tag k-skill'>과정·기능</span> 시차와 별의 밝기 공식을 활용해 항성까지의 거리를 계산하고 암흑 물질/암흑 에너지 데이터 분석하기"] }], careers: ["천문학자", "항공우주엔지니어", "데이터분석가"], majors: ["천문우주학과", "우주과학과", "물리학과"] },
    "과학과제 연구": { goal: "학생 스스로 과학적 연구 주제를 발굴하고 한 학기 동안 주도적으로 논문 형태의 보고서를 완성하여 대학 수준의 학술적 탐구력을 입증하는 진로 과목입니다.", contents: [{ t: "📌 영역: 연구 주제 선정 및 설계", l: ["<span class='k-tag k-know'>지식·이해</span> 선행 연구 분석, 가설 설정, 통제/조작 변인 등 연구 설계 방법론", "<span class='k-tag k-skill'>과정·기능</span> 창의적인 연구 주제를 도출하고 체계적인 실험 계획 수립하기"] }, { t: "📌 영역: 연구 수행 및 학술 소통", l: ["<span class='k-tag k-know'>지식·이해</span> 데이터 수집의 정확성과 통계적/시각적 처리 방법 및 연구 윤리", "<span class='k-tag k-skill'>과정·기능</span> 데이터를 해석하여 결론을 도출하고 학술 포스터 제작 및 동료 학술 비평(Peer Review) 수행하기"] }], careers: ["연구개발(R&D)연구관", "기초과학연구원", "대학교수"], majors: ["자연과학대학전반", "이공학부", "자율전공학부"] },
    "물리학 실험": { goal: "물리학의 주요 이론들을 실제 고도화된 실험 장비(MBL 센서 등)를 활용해 직접 검증하며, 실험 오차 분석 등 정통 실험 물리학의 기초를 다집니다.", contents: [{ t: "📌 영역: 역학, 전자기학 실험", l: ["<span class='k-tag k-know'>지식·이해</span> MBL(컴퓨터 기반 실험) 장비 사용법, 오차 전파, 유효 숫자 처리 규정", "<span class='k-tag k-skill'>과정·기능</span> 자유 낙하, 전자기 유도 현상을 센서로 측정하여 엑셀 등으로 그래프 모델링하고 수식 증명하기"] }], careers: ["연구실테크니션", "광학엔지니어", "물리학자"], majors: ["물리학과", "정밀기계공학과", "반도체공학과"] },
    "화학 실험": { goal: "대학 일반 화학 수준의 적정, 합성, 분광 실험을 직접 수행하며, 화학 물질의 정량적 분석 능력과 안전한 실험실 운영 수칙을 체득하는 과목입니다.", contents: [{ t: "📌 영역: 화학 정량 분석 및 합성", l: ["<span class='k-tag k-know'>지식·이해</span> 뷰렛, 피펫 등 정밀 초자 사용법, 흡광도(비어-람베르트 법칙), 화학 물질 안전 관리", "<span class='k-tag k-skill'>과정·기능</span> 아스피린 합성, 비타민C 산화 환원 적정, 분광 광도계를 이용한 미지 시료 농도 분석 수행하기"] }], careers: ["화학분석기사", "제약연구원", "화장품개발자"], majors: ["화학공학과", "화학과", "생명공학과"] },
    "생명과학 실험": { goal: "광학 현미경 관찰, 마이크로파이펫 사용, DNA 추출 등 생명공학 및 의학 연구실에서 실제 쓰이는 핵심 실험 테크닉을 익히는 전문 융합 과목입니다.", contents: [{ t: "📌 영역: 세포 관찰 및 분자 생물학 실험", l: ["<span class='k-tag k-know'>지식·이해</span> 현미경 배율 조작, 제한 효소, 전기 영동(Electrophoresis) 작동 원리", "<span class='k-tag k-skill'>과정·기능</span> 브래드포드 분석을 통한 단백질 정량, 구강 상피 세포 DNA 추출 및 전기 영동 밴드 분석하기"] }], careers: ["임상병리사", "바이오의약품개발자", "의학연구원"], majors: ["생명과학과", "의예과", "수의예과", "임상병리학과"] },
    "과학의 역사와 문화": { goal: "과학이 발전해 온 역사적 궤적을 철학적, 사회적 맥락과 함께 탐구하여 과학 기술이 인류 문화에 미친 영향을 폭넓게 통찰하는 융합 과목입니다.", contents: [{ t: "📌 영역: 과학사적 패러다임의 전환", l: ["<span class='k-tag k-know'>지식·이해</span> 코페르니쿠스 혁명, 진화론의 충격, 토마스 쿤의 패러다임 이론", "<span class='k-tag k-skill'>과정·기능</span> 특정 과학적 발견이 당시 종교, 문학, 사회 제도에 미친 파급 효과를 비판적 에세이로 작성하기"] }], careers: ["과학칼럼니스트", "과학철학자", "과학관큐레이터"], majors: ["과학사학과", "자율전공학부", "과학교육과"] },
    "융합과학 탐구": { goal: "자연 현상 및 첨단 기술에 내재된 물리, 화학, 생명과학, 지구과학적 요소를 경계 없이 융합하여 새로운 시각의 탐구 프로젝트를 기획하는 과목입니다.", contents: [{ t: "📌 영역: STEAM 융합 프로젝트", l: ["<span class='k-tag k-know'>지식·이해</span> 바이오미메틱스(생체모방기술), 우주 거주 기지(테라포밍) 등 융합 과학의 주요 테마", "<span class='k-tag k-skill'>과정·기능</span> 여러 과학 교과의 원리를 결합하여 미래형 친환경 이동 수단이나 스마트 팜 축소판 설계하기"] }], careers: ["융합기술연구원", "산업디자이너", "기술경영기획자"], majors: ["융합공학부", "기계전자공학부", "나노과학기술학과"] },
    "기후 변화와 환경 생태": { goal: "기후 위기와 생태계 파괴 현상을 공간적 데이터로 융합 분석하고 탄소 중립 시대를 이끌 환경 정책 대안을 기획하는 과목입니다.", contents: [{ t: "📌 영역: 기후 위기와 생태계", l: ["<span class='k-tag k-know'>지식·이해</span> 온실효과 메커니즘, 서식지 단편화가 생물 다양성에 미치는 영향", "<span class='k-tag k-skill'>과정·기능</span> 위성/과학 데이터를 활용하여 기후 재난 피해를 정량적으로 분석하고 실태 조사하기"] }, { t: "📌 영역: 지속 가능한 환경 정책", l: ["<span class='k-tag k-know'>지식·이해</span> 탄소 배출권, 파리 협정, 신재생 에너지 전환 원리", "<span class='k-tag k-skill'>과정·기능</span> 스마트 시티, 제로 웨이스트 시스템 등 지속 가능한 미래를 위한 정책 기획하기"] }], careers: ["환경영향평가사", "생태복원기사", "ESG기획자"], majors: ["환경공학과", "기후에너지공학과", "생태공학과"] },
